SELECT JOIN_REQUEST_NO , ASPIRATION , JR.STATUS , JR.JOIN_NO , JR.USER_ID , JB.USER_ID AS host FROM JOIN_REQUEST JR JOIN JOIN_BOARD JB ON(JB.JOIN_NO = JR.JOIN_NO) WHERE JB.USER_ID = #{userId}
AND JR.STATUS = #{status}
ORDER BY JOIN_REQUEST_NO DESC OFFSET #{offset} ROWS FETCH NEXT #{boardLimit} ROWS ONLY

SELECT JOIN_REQUEST_NO , ASPIRATION , JR.STATUS , JR.JOIN_NO , JR.USER_ID AS USER_ID , JB.USER_ID AS HOST , JB.CATEGORY AS CATEGORY , JB.TITLE AS TITLE , JB.CREATE_DATE AS CREATE_DATE FROM JOIN_REQUEST JR JOIN JOIN_BOARD JB ON(JB.JOIN_NO = JR.JOIN_NO) WHERE JR.USER_ID = #{userId}
AND JR.STATUS = #{status}
ORDER BY JOIN_REQUEST_NO DESC OFFSET #{offset} ROWS FETCH NEXT #{boardLimit} ROWS ONLY
